3389	\begin{lemma}[Locally surjective morphisms of presheaves]
3390	  \label{lem:presheaf_is_locally_surjective}
3391	  \lean{CategoryTheory.Presheaf.IsLocallySurjective}
3392	  \mathlibok
3393	  \textit{Provided by Mathlib.}
3394	  For a Grothendieck topology \(J\), a morphism \(\alpha : \mathcal{G} \to \mathcal{H}\) of presheaves
3395	  is \emph{locally surjective} when every section of \(\mathcal{H}\) over an object is, locally on a
3396	  covering sieve, in the image of \(\alpha\). On a topological space this is the predicate
3397	  \(\operatorname{TopCat.Presheaf.IsLocallySurjective}\): for each open \(V\) and each section
3398	  \(t \in \mathcal{H}(V)\) there is an open covering \(\{W_\alpha\}\) of \(V\) with \(t|_{W_\alpha}\)
3399	  in the image of \(\alpha_{W_\alpha}\).
3400	\end{lemma}
