3414	\begin{lemma}[Affine opens form a basis]
3415	  \label{lem:scheme_isBasis_affineOpens}
3416	  \lean{AlgebraicGeometry.Scheme.isBasis_affineOpens}
3417	  \mathlibok
3418	  \textit{Provided by Mathlib.}
3419	  The affine opens of a scheme \(X\) form a basis for its topology. On \(\operatorname{Spec} R\) this
3420	  refines any open covering of a distinguished open to one by basic/affine opens, the input that
3421	  turns a local-surjectivity covering into a standard cover lying in \(\mathrm{Cov}\)
3422	  (Lemma~\ref{lem:standard_cover_cofinal}).
3423	\end{lemma}
